#include <bits/stdc++.h>
using namespace std;
int a[32][32],bz[32][32],h[10005][4];
int dx[5]={-1,1,0,0};
int dy[5]={0,0,-1,1};
int n,i,j,m,x=0,y=0;
void bfs(int x,int y)
{
	 int i;
    if(x<0||x>n+1||y<0||y>n+1||a[x][y]!=0) return;
    a[x][y]=1;
    for (i=0;i<=3;i++)
		bfs(x+dx[i],y+dy[i]);
	return ;
}
int main(){
    scanf("%d",&n);
    m=n;
    for(i=1;i<=n;i++)
        for(j=1;j<=n;j++)
		{
            scanf("%d",&bz[i][j]);
            if(bz[i][j]==0) a[i][j]=0;
            else a[i][j]=2;
        }
    bfs(0,0);
    for(i=1;i<=n;i++)
	{
        for(j=1;j<=n;j++)
        {
        	if(a[i][j]==0)printf("2 ");
        	else printf("%d ",bz[i][j]);
		}
        printf("\n");
    }
    return 0;
}
